 1	import type { FC } from 'react';
 2	import type { VmData } from 'src/modules/Providers/views/details/tabs/VirtualMachines/components/VMCellProps';
 3	import { useForkliftTranslation } from 'src/utils/i18n';
 4	
 5	import {
 6	  HelperText,
 7	  HelperTextItem,
 8	  Label,
 9	  PageSection,
10	  PageSectionVariants,
11	} from '@patternfly/react-core';
12	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
13	import { EMPTY_MSG } from '@utils/constants';
14	import { isEmpty } from '@utils/helpers';
15	
16	import {
17	  getCategoryColor,
18	  getCategoryIcon,
19	  getCategoryTitle,
20	  groupConcernsByCategory,
21	} from '../utils/category';
22	import { orderedConcernCategories, type VirtualMachineWithConcerns } from '../utils/constants';
23	
24	import './ConcernsTable.scss';
25	
26	export const ConcernsTable: FC<{ vmData: VmData }> = ({ vmData }) => {
27	  const { t } = useForkliftTranslation();
28	
29	  const vm = vmData?.vm as VirtualMachineWithConcerns;
30	
31	  const concerns = vm?.concerns;
32	
33	  if (isEmpty(concerns)) {
34	    return (
35	      <PageSection variant={PageSectionVariants.light}>
36	        <HelperText>
37	          <HelperTextItem variant="indeterminate">
38	            {t('No concerns found for this virtual machine.')}
39	          </HelperTextItem>
40	        </HelperText>
41	      </PageSection>
42	    );
43	  }
44	
45	  const groupedConcerns = groupConcernsByCategory(concerns);
46	
47	  return (
48	    <PageSection variant={PageSectionVariants.light} className="concerns-table">
49	      <Table aria-label="Expandable table" variant="compact">
50	        <Thead>
51	          <Tr>
52	            <Th width={10}>{t('Label')}</Th>
53	            <Th width={10}>{t('Category')}</Th>
54	            <Th width={30}>{t('Assessment')}</Th>
55	          </Tr>
56	        </Thead>
57	        <Tbody>
58	          {orderedConcernCategories.map((category) =>
59	            groupedConcerns?.[category].map((concern) => (
60	              <Tr key={concern.label}>
61	                <Td modifier="truncate">{concern.label}</Td>
62	                <Td>
63	                  <Label
64	                    color={getCategoryColor(concern.category)}
65	                    icon={getCategoryIcon(concern.category)}
66	                  >
67	                    {getCategoryTitle(concern.category)}
68	                  </Label>
69	                </Td>
70	                <Td>{concern?.assessment || EMPTY_MSG}</Td>
71	              </Tr>
72	            )),
73	          )}
74	        </Tbody>
75	      </Table>
76	    </PageSection>
77	  );
78	};

